		firstDone <- struct {
			summary ExecutionCleanupSummary
			skipped bool
			err     error
		}{summary: summary, skipped: skipped, err: err}
	}()

	<-runner.started
	summary, skipped, err := runExecutionCleanupPass(context.Background(), projectRoot, runner, io.Discard, nil, "periodic")
	require.NoError(t, err)
