	// rely on the bundle id prefix.
	createdAt := time.Now().UTC().Format(time.RFC3339)
	if t2, err := time.Parse("20060102T150405", strings.SplitN(attemptID, "-", 2)[0]); err == nil {
		createdAt = t2.UTC().Format(time.RFC3339)
	}
